import datetime
from dataclasses import dataclass

SLA_DAYS = {
    "minor": 1,
    "material": 3,
    "significant": 5,
}

def sla_deadline(exception: BudgetException) -> datetime.datetime:
    tier_name = exception.tier.value
    business_days = SLA_DAYS[tier_name]
    # Simple version: calendar days (adjust for holidays in production)
    submitted = datetime.datetime.fromisoformat(exception.submitted_at)
    return submitted + datetime.timedelta(days=business_days)

def check_overdue_exceptions(exceptions: list) -> list:
    now = datetime.datetime.utcnow()
    overdue = []
    for ex in exceptions:
        if ex.status in (ExceptionStatus.SUBMITTED, ExceptionStatus.UNDER_REVIEW):
            if now > sla_deadline(ex):
                overdue.append(ex)
    return overdue

