from dataclasses import dataclass, field
from typing import Dict, List, Optional
import datetime

@dataclass
class BudgetLedgerEntry:
    team_id: str
    period: str                   # "2026-07"
    base_budget_usd: float
    approved_exceptions: list = field(default_factory=list)  # list of (exception_id, amount, approved_at)

    @property
    def effective_budget_usd(self) -> float:
        return self.base_budget_usd + sum(a[1] for a in self.approved_exceptions)

    def apply_exception(self, exception_id: str, amount_usd: float) -> None:
        """Called immediately when exception is approved."""
        self.approved_exceptions.append((
            exception_id,
            amount_usd,
            datetime.datetime.utcnow().isoformat()
        ))

@dataclass
class BudgetLedger:
    entries: Dict[str, BudgetLedgerEntry] = field(default_factory=dict)

    def _key(self, team_id: str, period: str) -> str:
        return f"{team_id}::{period}"

    def set_base_budget(self, team_id: str, period: str, amount_usd: float) -> None:
        key = self._key(team_id, period)
        self.entries[key] = BudgetLedgerEntry(team_id, period, amount_usd)

    def apply_approved_exception(
        self, team_id: str, period: str, exception_id: str, amount_usd: float
    ) -> None:
        key = self._key(team_id, period)
        self.entries[key].apply_exception(exception_id, amount_usd)
        # Guardrail system must be notified to refresh its threshold
        self._notify_guardrails(team_id, period)

    def effective_budget(self, team_id: str, period: str) -> float:
        return self.entries[self._key(team_id, period)].effective_budget_usd

